"use strict";(self.webpackChunkmagento2_hyva_jewellery_theme_docs=self.webpackChunkmagento2_hyva_jewellery_theme_docs||[]).push([[9026],{3882(e,t,n){n.r(t),n.d(t,{comp:()=>a,data:()=>i});var r=n(641);const o={},a=(0,n(6262).A)(o,[["render",function(e,t){return(0,r.uX)(),(0,r.CE)("div",null,[...t[0]||(t[0]=[(0,r.Fv)('<h1 id="header-footer-mega-menu-builder" tabindex="-1"><a class="header-anchor" href="#header-footer-mega-menu-builder"><span>Header, Footer &amp; Mega Menu Builder</span></a></h1><p>The <strong>Header &amp; Footer Builder</strong> lets you manage the store navigation, mega menus, header announcement, logo, and footer from Magento Admin.</p><p>Open it from <strong>Content → Homepage Configurator → Header &amp; Footer Builder</strong>.</p><p><img src="/hyva-jewelry-theme/screenshots/header-footer-builder-menu.png" alt="Magento Admin menu path for Header and Footer Builder"></p><p><img src="/hyva-jewelry-theme/screenshots/mega-menu.png" alt="Mega menu on the storefront"></p><h2 id="what-it-controls" tabindex="-1"><a class="header-anchor" href="#what-it-controls"><span>What it controls</span></a></h2><p>Use this builder to update these storefront areas:</p><table><thead><tr><th>Area</th><th>What you edit</th></tr></thead><tbody><tr><td><strong>Menu structure</strong></td><td>Add categories, pages, products, collections, and custom links. Reorder them by drag-and-drop.</td></tr><tr><td><strong>Item settings</strong></td><td>Change the label, link, description, visibility, submenu style, and promo images for a menu item.</td></tr><tr><td><strong>Header settings</strong></td><td>Announcement text, announcement link, and store logo.</td></tr><tr><td><strong>Footer settings</strong></td><td>Description, contact email, contact phone.</td></tr><tr><td><strong>Agent Readiness</strong></td><td>Optional settings for AI and search discovery.</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Save before checking the storefront</p><p>Previewing in the builder does not update the live storefront. Click <strong>Save Configuration</strong> after making changes.</p></div><h2 id="workflow-at-a-glance" tabindex="-1"><a class="header-anchor" href="#workflow-at-a-glance"><span>Workflow at a glance</span></a></h2><ol><li>Add categories, pages, products, or custom links to the <strong>Saved Menu Structure</strong>.</li><li>Drag to reorder and nest items into groups.</li><li>Click a row to edit its label, link, submenu style, and promo images.</li><li>Set header announcement, logo, and footer text.</li><li>(Optional) Configure <strong>Agent Readiness</strong>.</li><li>Click <strong>Save Configuration</strong>.</li></ol><p>Continue with <a href="/hyva-jewelry-theme/chrome/building-menu" target="_blank" rel="noopener noreferrer">Building the Menu</a>.</p>',12)])])}]]),i=JSON.parse('{"path":"/hyva-jewelry-theme/chrome/overview.html","title":"Header, Footer & Mega Menu Builder","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"What it controls","slug":"what-it-controls","link":"#what-it-controls","children":[]},{"level":2,"title":"Workflow at a glance","slug":"workflow-at-a-glance","link":"#workflow-at-a-glance","children":[]}],"git":{"contributors":[{"name":"anikesh kumar","username":"","email":"anikesh.kumar204@webkul.in","commits":1}],"changelog":[{"hash":"65ee1538c72e98b02c838952f96993746b91fe68","time":1783608557000,"email":"anikesh.kumar204@webkul.in","author":"anikesh kumar","message":"init"}]},"filePathRelative":"chrome/overview.md"}')}}]);